const ctx = this;
const IC = "https://inspiring-cat-production.up.railway.app";
const SA = "https://super-agent-production.up.railway.app";

async function httpGet(url) {
  try {
    const d = await ctx.helpers.httpRequest({ method: 'GET', url, timeout: 12000, ignoreHttpStatusErrors: true });
    return { ok: true, d };
  } catch(e) { return { ok: false, e: String(e.message) }; }
}
async function httpPost(url, payload) {
  try {
    const d = await ctx.helpers.httpRequest({
      method: 'POST', url,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      timeout: 20000, ignoreHttpStatusErrors: true
    });
    return { ok: true, d };
  } catch(e) { return { ok: false, e: String(e.message) }; }
}

const [ic, sa] = await Promise.all([httpGet(IC + '/health'), httpGet(SA + '/health')]);

const issues = [];
if (!ic.ok) issues.push({
  service: 'inspiring-cat', type: 'service_down', sev: 'critical',
  desc: 'inspiring-cat container unreachable - CLI, Playwright & shell tasks offline. Error: ' + ic.e,
  proposed_fix: 'Check Railway for OOM kill or container crash. Trigger redeploy.',
  fix_cmd: 'python3 /app/scripts/health_check.py'
});
if (!sa.ok) issues.push({
  service: 'super-agent', type: 'service_down', sev: 'critical',
  desc: 'super-agent API gateway unreachable - AI routing, dashboard & HTTP endpoints offline. Error: ' + sa.e,
  proposed_fix: 'Check Railway super-agent logs for FastAPI crash. Trigger redeploy.',
  fix_cmd: 'echo "Restart super-agent via Railway dashboard"'
});
if (ic.ok && ic.d && ic.d.claude_available === false) {
  const ttl = ic.d.claude_token_expires_in_s;
  issues.push({
    service: 'Claude CLI Pro', type: 'cli_auth',
    sev: (ttl !== undefined && ttl < 3600) ? 'critical' : 'high',
    desc: 'Claude CLI Pro auth failure (TOKEN ERR). Token TTL: ' + (ttl !== undefined ? Math.floor(ttl/60) + ' min' : 'unknown') + '. Pro-tier tasks degraded.',
    proposed_fix: 'Trigger full_recovery_chain(): direct OAuth refresh -> GitHub Actions relay -> Playwright browser login.',
    fix_cmd: "python3 -c \"import sys;sys.path.insert(0,'/app');from app.learning.cli_auto_login import full_recovery_chain;full_recovery_chain()\""
  });
}

if (issues.length === 0) {
  return [{ json: { action_count: 0, actions: [], ts: new Date().toISOString(), all_healthy: true } }];
}

const SETUP_PY = `import os,psycopg2
db=os.environ['DATABASE_URL'].replace('postgres://','postgresql://')
conn=psycopg2.connect(db);cur=conn.cursor()
cur.execute('''CREATE TABLE IF NOT EXISTS cos_pending_actions(
  id TEXT PRIMARY KEY,service TEXT,issue_type TEXT,severity TEXT,
  description TEXT,proposed_fix TEXT,fix_cmd TEXT,
  status TEXT DEFAULT 'pending',
  created_at TIMESTAMPTZ DEFAULT NOW(),
  expires_at TIMESTAMPTZ DEFAULT NOW()+INTERVAL '24 hours',
  approved_at TIMESTAMPTZ,executed_at TIMESTAMPTZ,
  response_channel TEXT,response_from TEXT,result TEXT)''')
cur.execute('''CREATE TABLE IF NOT EXISTS cos_config(
  key TEXT PRIMARY KEY,value TEXT,updated_at TIMESTAMPTZ DEFAULT NOW())''')
cur.execute('CREATE INDEX IF NOT EXISTS cos_idx ON cos_pending_actions(status,created_at)')
conn.commit();conn.close();print('SETUP_OK')`;

const setupB64 = Buffer.from(SETUP_PY).toString('base64');
const setupResp = await httpPost(IC + '/tasks', { type: 'shell', payload: { command: `python3 -c "import base64;exec(base64.b64decode('${setupB64}').decode())"` } });
const setupTask = setupResp.d;
for (let i = 0; i < 8; i++) {
  await new Promise(r => setTimeout(r, 2000));
  const s = await httpGet(IC + '/tasks/' + setupTask.id);
  if (s.d && (s.d.status === 'done' || s.d.status === 'error')) break;
}

const actions = [];
for (const iss of issues) {
  const aid = 'cos-' + Math.random().toString(16).slice(2, 10);
  const INSERT_PY = `import os,psycopg2
db=os.environ['DATABASE_URL'].replace('postgres://','postgresql://')
conn=psycopg2.connect(db);cur=conn.cursor()
cur.execute("SELECT id FROM cos_pending_actions WHERE service=%s AND status='pending' AND created_at>NOW()-INTERVAL '2 hours'",('` + iss.service + `',))
ex=cur.fetchone()
if ex:
    print('SKIP:'+ex[0])
else:
    cur.execute("INSERT INTO cos_pending_actions(id,service,issue_type,severity,description,proposed_fix,fix_cmd)VALUES(%s,%s,%s,%s,%s,%s,%s) ON CONFLICT DO NOTHING",
        ('` + aid + `','` + iss.service + `','` + iss.type + `','` + iss.sev + `',` + JSON.stringify(iss.desc) + `,` + JSON.stringify(iss.proposed_fix) + `,` + JSON.stringify(iss.fix_cmd) + `))
    conn.commit();print('OK:` + aid + `')
conn.close()`;
  const b64 = Buffer.from(INSERT_PY).toString('base64');
  const trResp = await httpPost(IC + '/tasks', { type: 'shell', payload: { command: `python3 -c "import base64;exec(base64.b64decode('${b64}').decode())"` } });
  const tr = trResp.d;
  let out = '', finalId = aid;
  for (let i = 0; i < 10; i++) {
    await new Promise(r => setTimeout(r, 2000));
    const s = await httpGet(IC + '/tasks/' + tr.id);
    if (s.d && (s.d.status === 'done' || s.d.status === 'error')) {
      out = s.d.output || '';
      if (out.includes('SKIP:')) finalId = (out.match(/SKIP:(cos-[a-f0-9]+)/) || ['', aid])[1];
      break;
    }
  }
  actions.push({ ...iss, action_id: finalId, is_new: !out.includes('SKIP:') });
}

return [{ json: { action_count: actions.filter(a => a.is_new).length, actions, ts: new Date().toISOString() } }];

const ctx = this;
const { actions, ts } = $input.first().json;
const IC = "https://inspiring-cat-production.up.railway.app";
const TG = "https://api.telegram.org/bot***REDACTED_TELEGRAM_BOT_TOKEN***";

async function httpGet(url) {
  try {
    const d = await ctx.helpers.httpRequest({ method: 'GET', url, timeout: 10000, ignoreHttpStatusErrors: true });
    return { ok: true, d };
  } catch(e) { return { ok: false, e: String(e.message) }; }
}
async function httpPost(url, payload) {
  try {
    const d = await ctx.helpers.httpRequest({
      method: 'POST', url,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      timeout: 15000, ignoreHttpStatusErrors: true
    });
    return { ok: true, d };
  } catch(e) { return { ok: false, e: String(e.message) }; }
}

const GET_CHAT_PY = `import os,psycopg2
db=os.environ['DATABASE_URL'].replace('postgres://','postgresql://')
conn=psycopg2.connect(db);cur=conn.cursor()
cur.execute("SELECT value FROM cos_config WHERE key='telegram_chat_id'")
row=cur.fetchone();print(row[0] if row else 'NONE');conn.close()`;
const gb64 = Buffer.from(GET_CHAT_PY).toString('base64');
const gtrResp = await httpPost(IC + '/tasks', { type: 'shell', payload: { command: `python3 -c "import base64;exec(base64.b64decode('${gb64}').decode())"` } });
const gtr = gtrResp.d;
let chatId = null;
for (let i = 0; i < 8; i++) {
  await new Promise(r => setTimeout(r, 2000));
  const s = await httpGet(IC + '/tasks/' + gtr.id);
  if (s.d && (s.d.status === 'done' || s.d.status === 'error')) {
    const v = (s.d.output || '').trim();
    if (v && v !== 'NONE') chatId = v;
    break;
  }
}

if (!chatId) {
  return [{ json: { sent: false, reason: 'No chat_id found. User must send any Telegram message to register.' } }];
}

const newActions = actions.filter(a => a.is_new);
const sevEmoji = { critical: '??', high: '??', medium: '??', low: '??' };

let msg = '?? <b>CHIEF OF STAFF - SYSTEM ALERT</b>\n';
msg += '<i>' + new Date(ts).toUTCString() + '</i>\n';
msg += '?????????????????????????????\n\n';
msg += newActions.length + ' issue' + (newActions.length !== 1 ? 's' : '') + ' detected - your approval required:\n\n';

const keyboard = [];
for (const a of newActions) {
  const se = sevEmoji[a.sev] || '?';
  msg += se + ' <b>' + a.service + '</b>\n';
  msg += '<code>' + a.action_id + '</code>  .  ' + a.sev.toUpperCase() + '\n';
  msg += a.desc + '\n\n';
  msg += '<b>Proposed fix:</b> ' + (a.proposed_fix || '').slice(0, 120) + '\n\n';
  keyboard.push([
    { text: '? Approve ' + a.action_id, callback_data: 'COS:A:' + a.action_id },
    { text: '? Reject ' + a.action_id,  callback_data: 'COS:R:' + a.action_id }
  ]);
}
msg += '?????????????????????????????\n';
msg += '<i>Use buttons or reply: APPROVE/REJECT + action ID\nExpires in 24 hours.</i>';

await httpPost(TG + '/sendMessage', { chat_id: chatId, text: msg, parse_mode: 'HTML', reply_markup: { inline_keyboard: keyboard } });

return [{ json: { sent: true, chat_id: chatId, notified: newActions.map(a => a.action_id) } }];

